contracts/AaveV3Adapter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

// Aave V3 Interface
interface IPool {
    function supply(address asset, uint256 amount, address onBehalfOf, uint16 referralCode) external;
    function withdraw(address asset, uint256 amount, address to) external returns (uint256);
}

interface IAToken is IERC20 {
    function UNDERLYING_ASSET_ADDRESS() external view returns (address);
}

/**
 * @title AaveV3Adapter
 * @dev REAL Aave V3 integration on Polygon mainnet
 * NOT A MOCK - Uses actual Aave V3 Pool contract
 */
contract AaveV3Adapter is Ownable {
    using SafeERC20 for IERC20;

    // Real Aave V3 Pool on Polygon PoS: 0x794a61358D6845594F94dc1DB02A252b5b4814aD
    IPool public constant AAVE_POOL = IPool(0x794a61358D6845594F94dc1DB02A252b5b4814aD);

    // Real aUSDC token on Polygon
    IAToken public immutable aToken;
    IERC20 public immutable asset;

    address public vault;

    event Deposited(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);

    constructor(address _asset, address _aToken) Ownable(msg.sender) {
        asset = IERC20(_asset);
        aToken = IAToken(_aToken);
        vault = msg.sender;
    }

    modifier onlyVault() {
        require(msg.sender == vault, "Only vault");
        _;
    }

    function setVault(address _vault) external onlyOwner {
        vault = _vault;
    }

    /**
     * @dev Deposit assets into REAL Aave V3
     */
    function deposit(uint256 amount) external onlyVault {
        require(amount > 0, "Amount must be > 0");

        // Transfer tokens from vault
        asset.safeTransferFrom(msg.sender, address(this), amount);

        // Approve Aave pool
        asset.approve(address(AAVE_POOL), amount);

        // Supply to REAL Aave V3
        AAVE_POOL.supply(address(asset), amount, address(this), 0);

        emit Deposited(msg.sender, amount);
    }

    /**
     * @dev Withdraw assets from REAL Aave V3
     */
    function withdraw(uint256 amount) external onlyVault {
        // Withdraw from REAL Aave V3
        uint256 withdrawn = AAVE_POOL.withdraw(address(asset), amount, msg.sender);

        emit Withdrawn(msg.sender, withdrawn);
    }

    /**
     * @dev Get balance with REAL accrued interest from Aave
     */
    function balanceOf(address user) external view returns (uint256) {
        // aTokens represent 1:1 with deposited amount + interest
        return aToken.balanceOf(address(this));
    }

    /**
     * @dev Get current REAL APY from Aave
     * Note: In production, you'd query Aave's data provider
     */
    function getCurrentAPY() external pure returns (uint256) {
        // This would query real Aave liquidity rates
        // For now, returns placeholder - real APY varies
        return 350; // Example: 3.50% (real Aave APY changes dynamically)
    }
}

contracts/MasterVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title MasterVault
 * @dev Main vault deployed on Polygon PoS (Amoy testnet)
 * Accepts user deposits and manages cross-chain yield strategies
 */
contract MasterVault is ERC20, Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // The underlying asset (e.g., USDC)
    IERC20 public immutable asset;

    // Strategy adapters (could be on this chain or referenced for cross-chain)
    address public aaveAdapter;
    address public rebalanceExecutor; // Cross-chain executor on zkEVM

    // TVL tracking
    uint256 public totalValueLocked;

    // Strategy allocations (in basis points, 10000 = 100%)
    mapping(address => uint256) public strategyAllocations;

    // Events
    event Deposited(address indexed user, uint256 assets, uint256 shares);
    event Withdrawn(address indexed user, uint256 assets, uint256 shares);
    event Rebalanced(address indexed strategy, uint256 amount, uint256 timestamp);
    event StrategyAdded(address indexed strategy, uint256 allocation);
    event CrossChainRebalanceInitiated(bytes32 indexed messageId, uint256 amount);

    constructor(
        address _asset,
        string memory _name,
        string memory _symbol
    ) ERC20(_name, _symbol) Ownable(msg.sender) {
        asset = IERC20(_asset);
    }

    /**
     * @dev Set Aave adapter address
     */
    function setAaveAdapter(address _aaveAdapter) external onlyOwner {
        require(_aaveAdapter != address(0), "Invalid address");
        aaveAdapter = _aaveAdapter;
        emit StrategyAdded(_aaveAdapter, 0);
    }

    /**
     * @dev Set RebalanceExecutor address (on zkEVM)
     */
    function setRebalanceExecutor(address _executor) external onlyOwner {
        require(_executor != address(0), "Invalid address");
        rebalanceExecutor = _executor;
    }

    /**
     * @dev Deposit assets and receive vault shares
     */
    function deposit(uint256 assets, address receiver) external nonReentrant returns (uint256 shares) {
        require(assets > 0, "Cannot deposit 0");
        require(receiver != address(0), "Invalid receiver");

        // Calculate shares to mint
        shares = totalSupply() == 0 ? assets : (assets * totalSupply()) / totalAssets();

        // Transfer assets from user
        asset.safeTransferFrom(msg.sender, address(this), assets);

        // Mint vault shares
        _mint(receiver, shares);

        // Update TVL
        totalValueLocked += assets;

        emit Deposited(receiver, assets, shares);

        return shares;
    }

    /**
     * @dev Withdraw assets by burning vault shares
     */
    function withdraw(
        uint256 shares,
        address receiver,
        address owner
    ) external nonReentrant returns (uint256 assets) {
        require(shares > 0, "Cannot withdraw 0");
        require(receiver != address(0), "Invalid receiver");

        // Check allowance if caller is not owner
        if (msg.sender != owner) {
            uint256 allowed = allowance(owner, msg.sender);
            require(allowed >= shares, "Insufficient allowance");
            _approve(owner, msg.sender, allowed - shares);
        }

        // Calculate assets to return
        assets = (shares * totalAssets()) / totalSupply();

        // Burn shares
        _burn(owner, shares);

        // Transfer assets to receiver
        asset.safeTransfer(receiver, assets);

        // Update TVL
        totalValueLocked -= assets;

        emit Withdrawn(receiver, assets, shares);

        return assets;
    }

    /**
     * @dev Rebalance funds into Aave adapter
     */
    function rebalanceToAave(uint256 amount) external onlyOwner nonReentrant {
        require(aaveAdapter != address(0), "Aave adapter not set");
        require(amount > 0 && amount <= asset.balanceOf(address(this)), "Invalid amount");

        // Approve adapter to spend tokens
        asset.approve(aaveAdapter, amount);

        // Call the adapter's deposit function
        (bool success, ) = aaveAdapter.call(
            abi.encodeWithSignature("deposit(uint256)", amount)
        );
        require(success, "Aave deposit failed");

        emit Rebalanced(aaveAdapter, amount, block.timestamp);
    }

    /**
     * @dev Withdraw from Aave adapter back to vault
     */
    function withdrawFromAave(uint256 amount) external onlyOwner nonReentrant {
        require(aaveAdapter != address(0), "Aave adapter not set");

        (bool success, ) = aaveAdapter.call(
            abi.encodeWithSignature("withdraw(uint256)", amount)
        );
        require(success, "Aave withdrawal failed");

        emit Rebalanced(aaveAdapter, amount, block.timestamp);
    }

    /**
     * @dev Initiate cross-chain rebalance (simulated for testnet)
     * In production, this would use Polygon AggLayer messaging
     */
    function initiateCrossChainRebalance(uint256 amount, bytes calldata data) external onlyOwner {
        require(rebalanceExecutor != address(0), "Executor not set");
        require(amount > 0, "Invalid amount");

        // For testnet: just emit event showing intent
        // In production: call AggLayer bridge contract
        bytes32 messageId = keccak256(abi.encodePacked(block.timestamp, amount, data));

        emit CrossChainRebalanceInitiated(messageId, amount);
    }

    /**
     * @dev Get total assets under management (TVL)
     */
    function totalAssets() public view returns (uint256) {
        uint256 idle = asset.balanceOf(address(this));

        // In production, query Aave adapter balance
        // For now, return idle + TVL
        return idle + totalValueLocked - idle;
    }

    /**
     * @dev Convert shares to assets
     */
    function convertToAssets(uint256 shares) external view returns (uint256) {
        uint256 supply = totalSupply();
        return supply == 0 ? shares : (shares * totalAssets()) / supply;
    }

    /**
     * @dev Convert assets to shares
     */
    function convertToShares(uint256 assets) external view returns (uint256) {
        uint256 supply = totalSupply();
        return supply == 0 ? assets : (assets * supply) / totalAssets();
    }

    /**
     * @dev Get vault TVL (same as totalAssets)
     */
    function getTVL() external view returns (uint256) {
        return totalAssets();
    }

    /**
     * @dev Emergency withdraw - owner only
     */
    function emergencyWithdraw(address token, uint256 amount) external onlyOwner {
        IERC20(token).safeTransfer(owner(), amount);
    }
}

contracts/MATICVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title MATICVault
 * @dev Vault that accepts native MATIC deposits directly (no conversion)
 * Perfect for Polygon buildathon - native token support!
 */
contract MATICVault is ERC20, Ownable, ReentrancyGuard {

    // TVL tracking
    uint256 public totalValueLocked;

    // Strategy adapters
    address public aaveAdapter;
    address public rebalanceExecutor;

    // Events
    event Deposited(address indexed user, uint256 amount, uint256 shares);
    event Withdrawn(address indexed user, uint256 amount, uint256 shares);
    event Rebalanced(address indexed strategy, uint256 amount, uint256 timestamp);

    constructor(
        string memory _name,
        string memory _symbol
    ) ERC20(_name, _symbol) Ownable(msg.sender) {}

    /**
     * @dev Deposit native MATIC and receive vault shares
     * @return shares The amount of vault shares minted
     */
    function deposit() external payable nonReentrant returns (uint256 shares) {
        require(msg.value > 0, "Must deposit MATIC");

        // Calculate shares to mint (1:1 ratio initially)
        // For a more sophisticated vault, use: shares = (msg.value * totalSupply()) / totalValueLocked
        if (totalSupply() == 0) {
            shares = msg.value; // Initial deposit: 1:1 ratio
        } else {
            shares = (msg.value * totalSupply()) / totalValueLocked;
        }

        // Update TVL
        totalValueLocked += msg.value;

        // Mint shares to depositor
        _mint(msg.sender, shares);

        emit Deposited(msg.sender, msg.value, shares);

        return shares;
    }

    /**
     * @dev Withdraw MATIC by burning vault shares
     * @param shares The amount of vault shares to burn
     * @return amount The amount of MATIC withdrawn
     */
    function withdraw(uint256 shares) external nonReentrant returns (uint256 amount) {
        require(shares > 0, "Must withdraw shares");
        require(balanceOf(msg.sender) >= shares, "Insufficient shares");

        // Calculate MATIC amount to return
        amount = (shares * totalValueLocked) / totalSupply();
        require(amount > 0, "Zero withdrawal amount");
        require(address(this).balance >= amount, "Insufficient vault balance");

        // Update TVL
        totalValueLocked -= amount;

        // Burn shares
        _burn(msg.sender, shares);

        // Transfer MATIC to user
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "MATIC transfer failed");

        emit Withdrawn(msg.sender, amount, shares);

        return amount;
    }

    /**
     * @dev Get user's MATIC balance in the vault
     * @param user The user address
     * @return The MATIC value of user's shares
     */
    function balanceOfAssets(address user) external view returns (uint256) {
        uint256 userShares = balanceOf(user);
        if (userShares == 0 || totalSupply() == 0) return 0;
        return (userShares * totalValueLocked) / totalSupply();
    }

    /**
     * @dev Preview how many shares would be minted for a deposit
     * @param amount The MATIC amount to deposit
     * @return shares The shares that would be minted
     */
    function previewDeposit(uint256 amount) external view returns (uint256 shares) {
        if (totalSupply() == 0) {
            return amount;
        }
        return (amount * totalSupply()) / totalValueLocked;
    }

    /**
     * @dev Preview how much MATIC would be received for burning shares
     * @param shares The shares to burn
     * @return amount The MATIC that would be received
     */
    function previewWithdraw(uint256 shares) external view returns (uint256 amount) {
        if (totalSupply() == 0) return 0;
        return (shares * totalValueLocked) / totalSupply();
    }

    /**
     * @dev Get vault total assets (TVL in MATIC)
     */
    function totalAssets() external view returns (uint256) {
        return totalValueLocked;
    }

    /**
     * @dev Set Aave adapter address
     */
    function setAaveAdapter(address _aaveAdapter) external onlyOwner {
        require(_aaveAdapter != address(0), "Invalid address");
        aaveAdapter = _aaveAdapter;
    }

    /**
     * @dev Set rebalance executor address
     */
    function setRebalanceExecutor(address _rebalanceExecutor) external onlyOwner {
        require(_rebalanceExecutor != address(0), "Invalid address");
        rebalanceExecutor = _rebalanceExecutor;
    }

    /**
     * @dev Allow contract to receive MATIC
     */
    receive() external payable {
        totalValueLocked += msg.value;
    }

    /**
     * @dev Fallback function
     */
    fallback() external payable {
        totalValueLocked += msg.value;
    }
}

